#include<bits/stdc++.h>
using namespace std;

string F(string s)
{
	int cnt = 0, n = s.size();
	for(char c : s) if(c == '1') cnt++;
	if(cnt == 0) return "A";
	else if(cnt == n) return "B";
	else
	{
		string s1 = s.substr(0, n / 2);
		string s2 = s.substr(n / 2, n / 2);
		return "C" + F(s1) + F(s2);
	}
}

int main()
{
	string str;
	cin >> str;
	cout << F(str);
	return 0;
}
